"""article 9 ec2."""

import math

from structuralcodes import codes

# 9.2.1 beams longitudinal
# 9.2.1.1 Minimum and maximum reinforcement areas


def As_min_beams(fctm, fyk, bl, d, *, W=None, z=None, fctm_fl=None, fyd=None):
    """Calculate the minimum tensile longitudinal reinforcement area in beams.

    EN 1992-1-1 (2004). Eq. (9.1N)

    Args:
        fctm (float): mean axial tensile strength of concrete in MPa.
        fyk (float): characteristic strength of reinforcement in MPa
        bl (float): mean width of the tension zone; for a T-beam with the flange in compression, only the
            width of the web is taken into account in calculating the value of b. Values in mm
        d (float): Effective depth in mm

    Additional parameters for the 'spain' national annex:
        W (float): [Description of W].
        z (float): [Description of z].
        fctm_fl (float): [Description of fctm_fl].
        fyd (float): [Description of fyd].

    Returns:
        float: The minimum longitudinal reinforcement area in mm².

    Raises:
        ValueError: If the required parameters of the national annex are not provided.
    """
    if codes._NATIONAL_ANNEX == 'spain':
        if None in (W, z, fctm_fl, fyd):
            raise ValueError("For the 'spain' national annex, parameters W, z, fctm_fl, and fyd must be provided.")
        return (W / z) * (fctm_fl / fyd)
    # Recommended value according to the standard.
    return max(0.26 * (fctm / fyk) * bl * d, 0.0013 * bl * d)


def As_max_beams(Ac):
    """Calculate the maximum longitudinal reinforcement area in beams outside lap locations.

    EN 1992-1-1 (2004). 9.2.1.1 (3)

    Args:
        Ac (float): Area of concrete section in mm2.

    Returns:
        float: (float): the maximum amount of longitudinal reinforcement in mm2.
    """
    return 0.04 * Ac


# 9.2.2 beams transversal reinforcement
def Asw_min_beams(fck, fyk, bw, alpha, *, fctm=None):
    """Calculate the minimum transversal reinforcement area in beams.

    EN 1992-1-1 (2004). (9.2.2)

    Args:
        fck (float): characteristic compressive strength of concrete in MPa.
        fyk (float): characteristic strength of reinforcement in MPa
        bw (float): is the width of the web in mm
        alpha (float): is the angle between shear reinforcement and the longitudinal axis in degrees

    Additional parameters for the 'spain' national annex:
        fctm (float): mean axial tensile strength of concrete in MPa.

    Returns:
        float: (float): the minimum amount of transversal reinforcement in mm2/mm.
    """
    _alpha(alpha)

    if codes._NATIONAL_ANNEX == 'spain':
        if fctm is None:
            raise ValueError("For the 'spain' national annex, parameters fctm must be provided.")
        Asw_min_s = fctm / 7.5 / fyk * (bw * math.sin(math.radians(alpha)))
    else:  # Recommended value according to the standard
        Asw_min_s = (0.08 * math.sqrt(fck) / fyk) * (bw * math.sin(math.radians(alpha)))

    return Asw_min_s


def _alpha(alpha: float) -> None:
    """Check if the provided angle alpha is within the bounds provided by the
    code.

    EN 1992-1-1 (2004). 9.2.2 (1)

    Args:
        alpha (float): s the angle between shear reinforcement and the longitudinal axis in degrees.

    Raises:
        ValueError if the chosen angle is not within the given bounds.
    """
    if alpha < 45 or alpha > 90:
        raise ValueError('angle of shear reinforcement should range from 45 to 90 deg.')


# 9.5 Columns
def As_min_columns(Ned, fyd, Ac):
    """Calculate the minimum longitudinal reinforcement area in columns.

    EN 1992-1-1 (2004). - 9.5.2 Eq. (9.1.2N)

    Args:
        Ned (float): Design axial compression force in N
        fyd (float): Design yield strength of the reinforcement in MPa
        Ac (float): Area of concrete section in mm2.

    Returns:
        float: (float): the minimum longituinal reinforcement in mm2.
    """
    if codes._NATIONAL_ANNEX == 'spain':
        As_min = max(0.1 * Ned / fyd, 0.004 * Ac / fyd)
    else:  # Recommended value according to the standard
        As_min = max(0.1 * Ned / fyd, 0.002 * Ac)

    return As_min


def As_max_columns(Ac, *, fcd=None, fyd=None):
    """Calculate the maximum longitudinal reinforcement area in columns outside lap locations. This limit may be doubled
       at laps.

    EN 1992-1-1 (2004). - 9.5.2 (3)

    Args:
        Ac (float): Area of concrete section in mm2.

    Additional parameters for the 'spain' national annex:
        fcd (float): mean axial tensile strength of concrete in MPa.
        fyd (float): Design yield strength of the reinforcement in MPa
    Returns:
        "NONE" : float: (float): the maximum longituinal reinforcement in mm2.
        "spain" : float: (float): the maximum longituinal reinforcement in each face mm2.
    """
    if codes._NATIONAL_ANNEX == 'spain':
        if None in (fcd, fyd):
            raise ValueError("For the 'spain' national annex, parameters fcd and fyd must be provided.")
        fyed = min(fyd, 400)
        return 0.5 * fcd * Ac / fyed
    # Recommended value according to the standard
    return 0.04 * Ac


# 9.6 Walls
def Asv_min_walls(Ac, *, fyk=None, fyd=None, fcd=None):
    """Calculate the mminumum vertical reinforcement area in walls. Half of this area should be located at each face.

    EN 1992-1-1 (2004). - 9.6.2 (1)

    Args:
        Ac (float): Area of concrete section in mm2.

    Returns:
        (Asv_min_t,Asv_min_c): (float): the mmin. vertical reinforcement in the tensile face and compression face mm2.
    """
    if codes._NATIONAL_ANNEX == 'spain':
        if None in (fyk, fcd, fyd):
            raise ValueError("For the 'spain' national annex, parameters fyk fcd and fyd must be provided.")
        Asv_min_t = 0.0009 * Ac if fyk == 500 else 0.0012 * Ac
        Asv_min_t = max(Asv_min_t, 0.04 * Ac * fcd / fyd)
        Asv_min_c = 0.3 * Asv_min_t
        return (Asv_min_t, Asv_min_c)
    As_min = 0.002 * Ac
    return (0.5 * As_min, 0.5 * As_min)


def Asv_max_walls(Ac):
    """Calculate the maximum vertical reinforcement area in walls outside lap locations.This limit may be doubled at
    laps.

    EN 1992-1-1 (2004). - 9.6.2 (1)

    Args:
        Ac (float): Area of concrete section in mm2.

    Returns:
        float: (float): the maximum vertical reinforcement in mm2.
    """
    return 0.04 * Ac


def Ash_min_walls(Ac, *, fyk=None, thk_wall=None, tall_wall=False, close_joints=False):
    """Calculate the mminumum horizontal reinforcement area in walls.

    EN 1992-1-1 (2004). - 9.6.3 (1)

    Args:
        Ac (float): Area of concrete section in mm2.

    Additional parameters for the 'spain' national annex:
        fyk (float): Characteristic yield strength of the reinforcement in MPa
        thk_wall (float): thicknes of the wall in mm
        tall_wall (float): If the height of the shaft of the wall is higher than 2.5m and depth of the foundation
        close_joints (bool): if vertical contraction joints spaced lessh than 7.5m
    Returns:
        (float): the mminumum horizontal reinforcement in mm2 in each face.
    """
    if codes._NATIONAL_ANNEX == 'spain':
        if None in (fyk, thk_wall, tall_wall, close_joints):
            raise ValueError("For the 'spain' national annex, parameters fyk,h_wall and thk_wall must be provided.")
        Ac = 500 * Ac / thk_wall if thk_wall > 500 else Ac
        Ash_min = 0.002 * Ac if (tall_wall or close_joints) else (0.0032 * Ac if fyk == 500 else 0.004 * Ac)
        Ash_min *= 0.5  # Spanish annex gives reinforcement in both faces.
    else:
        Ash_min = max(0.25 * Asv_min_walls(Ac)[0], 0.001 * Ac)
    return Ash_min


def As_min_depth_beams(Ac, perimenter):
    """Calculate the mminumum reinforcement area in depth bemas.

    EN 1992-1-1 (2004). - 9.7 (1)

    Args:
        Ac (float): Area section in mm2.
        perimeter (float): Perimeter in mm
    Returns:
        (float): the mminumum total reinforcement.
    """
    return max(0.1 / 100 * Ac, 150 * perimenter)


def As_min_bored_piles(Ac):
    """Mminumum reinforcement in bored piles."""
    if Ac < 0.5 * 1e-6:
        return 0.005 * Ac
    if Ac < 1 * 1e-6:
        return 2500
    return 0.0025 * Ac
